INSERT INTO `vulnerabilities` (`id`, `target_id`, `vendor`, `product`, `cve_id`, `description`, `first_seen`, `last_seen`) VALUES
(1, 5, 'thekelleys', 'dnsmasq', 'CVE-2023-28450', 'An issue was discovered in Dnsmasq before 2.90. The default maximum EDNS.0 UDP packet size was set to 4096 but should be 1232 because of DNS Flag Day 2020.', '2026-03-05 15:21:59', '2026-03-05 15:21:59'),
(2, 5, 'microsoft', 'ftp_service', 'CVE-2012-2532', 'Microsoft FTP Service 7.0 and 7.5 for Internet Information Services (IIS) processes unspecified commands before TLS is enabled for a session, which allows remote attackers to obtain sensitive information by reading the replies to these commands, aka \"FTP Command Injection Vulnerability.\"', '2026-03-05 15:22:00', '2026-03-05 15:22:00'),
(3, 5, 'microsoft', 'windows', 'CVE-1999-0524', 'ICMP information such as (1) netmask and (2) timestamp is allowed from arbitrary hosts.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(4, 5, 'microsoft', 'windows', 'CVE-1999-0289', 'The Apache web server for Win32 may provide access to restricted files when a . (dot) is appended to a requested URL.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(5, 5, 'microsoft', 'windows', 'CVE-2005-1891', 'The GIF parser in ateimg32.dll in AOL Instant Messenger (AIM) 5.9.3797 and earlier allows remote attackers to cause a denial of service (crash) via a malformed buddy icon that causes an integer underflow in a loop counter variable.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(6, 5, 'microsoft', 'windows', 'CVE-2007-0712', 'Heap-based buffer overflow in Apple QuickTime before 7.1.5 allows remote user-assisted attackers to cause a denial of service (crash) and possibly execute arbitrary code via a crafted MIDI file.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(7, 5, 'microsoft', 'windows', 'CVE-2007-5473', 'StaticFileHandler.cs in System.Web in Mono before 1.2.5.2, when running on Windows, allows remote attackers to obtain source code of sensitive files via a request containing a trailing (1) space or (2) dot, which is not properly handled by XSP.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(8, 5, 'microsoft', 'windows', 'CVE-2007-6404', 'Directory traversal vulnerability in Sergey Lyubka Simple HTTPD (shttpd) 1.38 and earlier on Windows allows remote attackers to read arbitrary files via a ..\\ (dot dot backslash) in the URI.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(9, 5, 'microsoft', 'windows', 'CVE-2008-0296', 'Heap-based buffer overflow in the libaccess_realrtsp plugin in VideoLAN VLC Media Player 0.8.6d and earlier on Windows might allow remote RTSP servers to cause a denial of service (application crash) or execute arbitrary code via a long string.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(10, 5, 'microsoft', 'windows', 'CVE-2008-0454', 'Cross-zone scripting vulnerability in the Internet Explorer web control in Skype 3.6.0.244, and earlier 3.5.x and 3.6.x versions, on Windows allows user-assisted remote attackers to inject arbitrary web script or HTML in the Local Machine Zone via the Title field of a (1) Dailymotion and possibly (2) Metacafe movie in the Skype video gallery, accessible through a search within the \"Add video to chat\" dialog, aka \"videomood XSS.\"', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(11, 5, 'microsoft', 'windows', 'CVE-2008-3897', 'DiskCryptor 0.2.6 on Windows stores pre-boot authentication passwords in the BIOS Keyboard buffer and does not clear this buffer before and after use, which allows local users to obtain sensitive information by reading the physical memory locations associated with this buffer.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(12, 5, 'microsoft', 'windows', 'CVE-2008-3012', 'gdiplus.dll in GDI+ in Microsoft Internet Explorer 6 SP1, Windows XP SP2 and SP3, Server 2003 SP1 and SP2, Vista Gold and SP1, Server 2008, Office XP SP3, Office 2003 SP2 and SP3, 2007 Microsoft Office System Gold and SP1, Visio 2002 SP2, PowerPoint Viewer 2003, Works 8, Digital Image Suite 2006, SQL Server 2000 Reporting Services SP2, SQL Server 2005 SP2, Report Viewer 2005 SP1 and 2008, and Forefront Client Security 1.0 does not properly perform memory allocation, which allows remote attackers to execute arbitrary code via a malformed EMF image file, aka \"GDI+ EMF Memory Corruption Vulnerability.\"', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(13, 5, 'microsoft', 'windows', 'CVE-2008-4293', 'Unspecified vulnerability in Opera before 9.52 on Windows, when registered as a protocol handler, allows remote attackers to cause a denial of service (crash) and possibly execute arbitrary code via unknown vectors in which Opera is launched by other applications.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(14, 5, 'microsoft', 'windows', 'CVE-2008-5112', 'The LDAP server in Active Directory in Microsoft Windows 2000 SP4 and Server 2003 SP1 and SP2 responds differently to a failed bind attempt depending on whether the user account exists and is permitted to login, which allows remote attackers to enumerate valid usernames via a series of LDAP bind requests, as demonstrated by ldapuserenum.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(15, 5, 'microsoft', 'windows', 'CVE-2009-0123', 'Unspecified vulnerability in Apple Safari on Mac OS X 10.5 and Windows allows remote attackers to read arbitrary files on a client machine via vectors related to the association of Safari with the (1) feed, (2) feeds, and (3) feedsearch URL types for RSS feeds.  NOTE: as of 20090114, the only disclosure is a vague pre-advisory. However, because it is from a well-known researcher, it is being assigned a CVE identifier for tracking purposes.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(16, 5, 'microsoft', 'windows', 'CVE-2009-0321', 'Apple Safari 3.2.1 (aka AppVer 3.525.27.1) on Windows allows remote attackers to cause a denial of service (infinite loop or access violation) via a link to an http URI in which the authority (aka hostname) portion is either a (1) . (dot) or (2) .. (dot dot) sequence.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(17, 5, 'microsoft', 'windows', 'CVE-2009-0437', 'The Installation Factory installation process for IBM WebSphere Application Server (WAS) 6.0.2 on Windows, when WAS is registered as a Windows service, allows local users to obtain sensitive information by reading the logs/instconfigifwas6.log log file.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(18, 5, 'microsoft', 'windows', 'CVE-2008-6194', 'Memory leak in the DNS server in Microsoft Windows allows remote attackers to cause a denial of service (memory consumption) via DNS packets.  NOTE: this issue reportedly exists because of an incorrect fix for CVE-2007-3898.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(19, 5, 'microsoft', 'windows', 'CVE-2009-0778', 'The icmp_send function in net/ipv4/icmp.c in the Linux kernel before 2.6.25, when configured as a router with a REJECT route, does not properly manage the Protocol Independent Destination Cache (aka DST) in some situations involving transmission of an ICMP Host Unreachable message, which allows remote attackers to cause a denial of service (connectivity outage) by sending a large series of packets to many destination IP addresses within this REJECT route, related to an \"rt_cache leak.\"', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(20, 5, 'microsoft', 'windows', 'CVE-2009-1072', 'nfsd in the Linux kernel before 2.6.28.9 does not drop the CAP_MKNOD capability before handling a user request in a thread, which allows local users to create device nodes, as demonstrated on a filesystem that has been exported with the root_squash option.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(21, 5, 'microsoft', 'windows', 'CVE-2007-6722', 'Vidalia bundle before 0.1.2.18, when running on Windows and Mac OS X, installs Privoxy with a configuration file (config.txt or config) that contains insecure (1) enable-remote-toggle and (2) enable-edit-actions settings, which allows remote attackers to bypass intended access restrictions and modify configuration.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(22, 5, 'microsoft', 'windows', 'CVE-2007-6723', 'TorK before 0.22, when running on Windows and Mac OS X, installs Privoxy with a configuration file (config.txt or config) that contains insecure (1) enable-remote-toggle and (2) enable-edit-actions settings, which allows remote attackers to bypass intended access restrictions and modify configuration.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(23, 5, 'microsoft', 'windows', 'CVE-2007-6724', 'Vidalia bundle before 0.1.2.18, when running on Windows, installs Privoxy with a configuration file (config.txt or config) that contains an insecure enable-remote-http-toggle setting, which allows remote attackers to bypass intended access restrictions and modify configuration.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(24, 5, 'microsoft', 'windows', 'CVE-2009-1233', 'Apple Safari 3.2.2 and 4 Beta on Windows allows remote attackers to cause a denial of service (application crash) via an XML document containing many nested A elements.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(25, 5, 'microsoft', 'windows', 'CVE-2009-1792', 'The system.openURL function in StoneTrip Ston3D StandalonePlayer (aka S3DPlayer StandAlone) 1.6.2.4 and 1.7.0.1 and WebPlayer (aka S3DPlayer Web) 1.6.0.0 allows remote attackers to execute arbitrary commands via shell metacharacters in the first argument (the sURL argument).', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(26, 5, 'microsoft', 'windows', 'CVE-2009-3097', 'Multiple unspecified vulnerabilities in HP Performance Insight 5.3 on Windows allow attackers to obtain sensitive information via unknown vectors, as demonstrated by certain modules in VulnDisco Pack Professional 8.11.  NOTE: as of 20090903, this disclosure has no actionable information. However, because the VulnDisco Pack author is a reliable researcher, the issue is being assigned a CVE identifier for tracking purposes.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(27, 5, 'microsoft', 'windows', 'CVE-2009-1965', 'Unspecified vulnerability in the Net Foundation Layer component in Oracle Database 9.2.0.8 and 10.1.0.5 allows remote attackers to affect confidentiality, integrity, and availability via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(28, 5, 'microsoft', 'windows', 'CVE-2009-1992', 'Unspecified vulnerability in the Core RDBMS component in Oracle Database 9.2.0.8, 10.1.0.5, and 10.2.0.4 allows remote attackers to affect confidentiality, integrity, and availability via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(29, 5, 'microsoft', 'windows', 'CVE-2009-3885', 'Sun Java SE 5.0 before Update 22 and 6 before Update 17 on Windows allows remote attackers to cause a denial of service via a BMP file containing a link to a UNC share pathname for an International Color Consortium (ICC) profile file, probably a related issue to CVE-2007-2789, aka Bug Id 6632445.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(30, 5, 'microsoft', 'windows', 'CVE-2009-4186', 'Stack consumption vulnerability in Apple Safari 4.0.3 on Windows allows remote attackers to cause a denial of service (application crash) via a long URI value (aka url) in the Cascading Style Sheets (CSS) background property.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(31, 5, 'microsoft', 'windows', 'CVE-2003-1579', 'Sun ONE (aka iPlanet) Web Server 6 on Windows, when DNS resolution is enabled for client IP addresses, uses a logging format that does not identify whether a dotted quad represents an unresolved IP address, which allows remote attackers to spoof IP addresses via crafted DNS responses containing numerical top-level domains, as demonstrated by a forged 123.123.123.123 domain name, related to an \"Inverse Lookup Log Corruption (ILLC)\" issue.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(32, 5, 'microsoft', 'windows', 'CVE-2010-0657', 'Google Chrome before 4.0.249.78 on Windows does not perform the expected encoding, escaping, and quoting for the URL in the --app argument in a desktop shortcut, which allows user-assisted remote attackers to execute arbitrary programs or obtain sensitive information by tricking a user into creating a crafted shortcut.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(33, 5, 'microsoft', 'windows', 'CVE-2009-4653', 'Stack-based buffer overflow in the dhost module in Novell eDirectory 8.8 SP5 for Windows allows remote authenticated users to cause a denial of service (dhost.exe crash) and possibly execute arbitrary code via a long string to /dhost/modules?I:.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(34, 5, 'microsoft', 'windows', 'CVE-2009-4654', 'Stack-based buffer overflow in the dhost module in Novell eDirectory 8.8 SP5 for Windows allows remote authenticated users to execute arbitrary code via long sadminpwd and verifypwd parameters in a submit action to /dhost/httpstk.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(35, 5, 'microsoft', 'windows', 'CVE-2010-0924', 'cfnetwork.dll 1.450.5.0 in CFNetwork, as used by safari.exe 531.21.10 in Apple Safari 4.0.3 and 4.0.4 on Windows, allows remote attackers to cause a denial of service (application crash) via a long string in the BACKGROUND attribute of a BODY element.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(36, 5, 'microsoft', 'windows', 'CVE-2010-0925', 'cfnetwork.dll 1.450.5.0 in CFNetwork, as used by safari.exe 531.21.10 in Apple Safari 4.0.4 on Windows, allows remote attackers to cause a denial of service (application crash) via a long string in the SRC attribute of a (1) IMG or (2) IFRAME element.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(37, 5, 'microsoft', 'windows', 'CVE-2009-4764', 'Adobe Reader 8.x and 9.x on Windows is able to execute EXE files that are embedded in a PDF document, which makes it easier for remote attackers to trick users into executing arbitrary code via a crafted document.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(38, 5, 'microsoft', 'windows', 'CVE-2010-1240', 'Adobe Reader and Acrobat 9.x before 9.3.3, and 8.x before 8.2.3 on Windows and Mac OS X, do not restrict the contents of one text field in the Launch File warning dialog, which makes it easier for remote attackers to trick users into executing an arbitrary local program that was specified in a PDF document, as demonstrated by a text field that claims that the Open button will enable the user to read an encrypted message.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(39, 5, 'microsoft', 'windows', 'CVE-2010-1034', 'Unspecified vulnerability in HP System Management Homepage (SMH) 6.0 before 6.0.0-95 on Linux, and 6.0 before 6.0.0.96 on Windows, allows remote authenticated users to obtain sensitive information, modify data, and cause a denial of service via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(40, 5, 'microsoft', 'windows', 'CVE-2010-1729', 'WebKit.dll in WebKit, as used in Safari.exe 4.531.9.1 in Apple Safari, allows remote attackers to cause a denial of service (application crash) via JavaScript that writes <marquee> sequences in an infinite loop.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(41, 5, 'microsoft', 'windows', 'CVE-2010-1549', 'Unspecified vulnerability in the Agent in HP LoadRunner before 9.50 and HP Performance Center before 9.50 allows remote attackers to execute arbitrary code via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(42, 5, 'microsoft', 'windows', 'CVE-2010-1556', 'Unspecified vulnerability in HP Systems Insight Manager (SIM) 5.3, 5.3 Update 1, and 6.0 allows remote attackers to obtain sensitive information and modify data via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(43, 5, 'microsoft', 'windows', 'CVE-2010-2263', 'nginx 0.8 before 0.8.40 and 0.7 before 0.7.66, when running on Windows, allows remote attackers to obtain source code or unparsed content of arbitrary files under the web document root by appending ::$DATA to the URI.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(44, 5, 'microsoft', 'windows', 'CVE-2010-2428', 'Cross-site scripting (XSS) vulnerability in admin_loginok.html in the Administrator web interface in Wing FTP Server for Windows 3.5.0 and earlier allows remote attackers to inject arbitrary web script or HTML via a crafted POST request.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(45, 5, 'microsoft', 'windows', 'CVE-2010-2594', 'Multiple cross-site request forgery (CSRF) vulnerabilities in the web management interface in InterSect Alliance Snare Agent 3.2.3 and earlier on Solaris, Snare Agent 3.1.7 and earlier on Windows, Snare Agent 1.5.0 and earlier on Linux and AIX, Snare Agent 1.4 and earlier on IRIX, Snare Epilog 1.5.3 and earlier on Windows, and Snare Epilog 1.2 and earlier on UNIX allow remote attackers to hijack the authentication of administrators for requests that (1) change the password or (2) change the listening port.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(46, 5, 'microsoft', 'windows', 'CVE-2010-0899', 'Unspecified vulnerability in Oracle Secure Backup 10.3.0.1 allows remote authenticated users to affect confidentiality, integrity, and availability via unknown vectors, a different vulnerability than CVE-2010-0898, CVE-2010-0907, and CVE-2010-0906.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(47, 5, 'microsoft', 'windows', 'CVE-2010-0900', 'Unspecified vulnerability in the Network Layer component in Oracle Database Server 9.2.0.8, 10.1.0.5, 10.2.0.4, 11.1.0.7, and 11.2.0.1, when running on Windows, allows remote attackers to affect availability via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(48, 5, 'microsoft', 'windows', 'CVE-2010-0903', 'Unspecified vulnerability in the Net Foundation Layer component in Oracle Database Server 9.2.0.8, 10.1.0.5, 10.2.0.4, 11.1.0.7, and 11.2.0.1, when running on Windows, allows remote attackers to affect availability via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(49, 5, 'microsoft', 'windows', 'CVE-2010-0019', 'Microsoft Silverlight 3 before 3.0.50611.0 on Windows, and before 3.0.41130.0 on Mac OS X, does not properly handle pointers, which allows remote attackers to execute arbitrary code or cause a denial of service (memory corruption and framework outage) via a crafted web site, aka \"Microsoft Silverlight Memory Corruption Vulnerability.\"', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(50, 5, 'microsoft', 'windows', 'CVE-2010-1898', 'The Common Language Runtime (CLR) in Microsoft .NET Framework 2.0 SP1, 2.0 SP2, 3.5, 3.5 SP1, and 3.5.1, and Microsoft Silverlight 2 and 3 before 3.0.50611.0 on Windows and before 3.0.41130.0 on Mac OS X, does not properly handle interfaces and delegations to virtual methods, which allows remote attackers to execute arbitrary code via (1) a crafted XAML browser application (aka XBAP), (2) a crafted ASP.NET application, or (3) a crafted .NET Framework application, aka \"Microsoft Silverlight and Microsoft .NET Framework CLR Virtual Method Delegate Vulnerability.\"', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(51, 5, 'microsoft', 'windows', 'CVE-2010-3143', 'Untrusted search path vulnerability in Microsoft Windows Contacts allows local users, and possibly remote attackers, to execute arbitrary code and conduct DLL hijacking attacks via a Trojan horse wab32res.dll that is located in the same folder as a .contact, .group, .p7c, .vcf, or .wab file.  NOTE: the codebase for this product may overlap the codebase for the product referenced in CVE-2010-3147.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(52, 5, 'microsoft', 'windows', 'CVE-2010-3888', 'Unspecified vulnerability in Microsoft Windows on 32-bit platforms allows local users to gain privileges via unknown vectors, as exploited in the wild in July 2010 by the Stuxnet worm, and identified by Kaspersky Lab researchers and other researchers.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(53, 5, 'microsoft', 'windows', 'CVE-2010-3889', 'Unspecified vulnerability in Microsoft Windows on 32-bit platforms allows local users to gain privileges via unknown vectors, as exploited in the wild in July 2010 by the Stuxnet worm, and identified by Microsoft researchers and other researchers.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(54, 5, 'microsoft', 'windows', 'CVE-2010-4368', 'awstats.cgi in AWStats before 7.0 on Windows accepts a configdir parameter in the URL, which allows remote attackers to execute arbitrary commands via a crafted configuration file located at a UNC share pathname.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(55, 5, 'microsoft', 'windows', 'CVE-2010-4587', 'Opera before 11.00 on Windows does not properly implement the Insecure Third Party Module warning message, which might make it easier for user-assisted remote attackers to have an unspecified impact via a crafted module.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(56, 5, 'microsoft', 'windows', 'CVE-2010-4114', 'Cross-site scripting (XSS) vulnerability in HP Discovery & Dependency Mapping Inventory (DDMI) 2.5x, 7.5x, and 7.6x allows remote attackers to inject arbitrary web script or HTML via unspecified vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(57, 5, 'microsoft', 'windows', 'CVE-2011-0638', 'Microsoft Windows does not properly warn the user before enabling additional Human Interface Device (HID) functionality over USB, which allows user-assisted attackers to execute arbitrary programs via crafted USB data, as demonstrated by keyboard and mouse data sent by malware on a smartphone that the user connected to the computer.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(58, 5, 'microsoft', 'windows', 'CVE-2011-0754', 'The SplFileInfo::getType function in the Standard PHP Library (SPL) extension in PHP before 5.3.4 on Windows does not properly detect symbolic links, which might make it easier for local users to conduct symlink attacks by leveraging cross-platform differences in the stat structure, related to lack of a FILE_ATTRIBUTE_REPARSE_POINT check.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(59, 5, 'microsoft', 'windows', 'CVE-2011-2806', 'Google Chrome before 13.0.782.215 on Windows does not properly handle vertex data, which allows remote attackers to execute arbitrary code or cause a denial of service (memory corruption) via unspecified vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(60, 5, 'microsoft', 'windows', 'CVE-2011-2822', 'Google Chrome before 13.0.782.215 on Windows does not properly parse URLs located on the command line, which has unspecified impact and attack vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(61, 5, 'microsoft', 'windows', 'CVE-2011-4693', 'Unspecified vulnerability in Adobe Flash Player 11.1.102.55 on Windows and Mac OS X allows remote attackers to execute arbitrary code via a crafted SWF file, as demonstrated by the first of two vulnerabilities exploited by the Intevydis vd_adobe_fp module in VulnDisco Step Ahead (SA).  NOTE: as of 20111207, this disclosure has no actionable information. However, because the module author is a reliable researcher, the issue is being assigned a CVE identifier for tracking purposes.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(62, 5, 'microsoft', 'windows', 'CVE-2011-4694', 'Unspecified vulnerability in Adobe Flash Player 11.1.102.55 on Windows and Mac OS X allows remote attackers to execute arbitrary code via a crafted SWF file, as demonstrated by the second of two vulnerabilities exploited by the Intevydis vd_adobe_fp module in VulnDisco Step Ahead (SA).  NOTE: as of 20111207, this disclosure has no actionable information. However, because the module author is a reliable researcher, the issue is being assigned a CVE identifier for tracking purposes.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(63, 5, 'microsoft', 'windows', 'CVE-2011-4725', 'Multiple SQL injection vulnerabilities in the Server Administration Panel in Parallels Plesk Panel 10.2.0_build1011110331.18 allow remote attackers to execute arbitrary SQL commands via crafted input to a PHP script, as demonstrated by login_up.php3 and certain other files.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(64, 5, 'microsoft', 'windows', 'CVE-2011-4726', 'Multiple cross-site scripting (XSS) vulnerabilities in the Server Administration Panel in Parallels Plesk Panel 10.2.0_build1011110331.18 allow remote attackers to inject arbitrary web script or HTML via crafted input to a PHP script, as demonstrated by admin/health/ and certain other files.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(65, 5, 'microsoft', 'windows', 'CVE-2011-4727', 'The Server Administration Panel in Parallels Plesk Panel 10.2.0_build1011110331.18 does not properly validate string data that is intended for storage in an XML document, which allows remote attackers to cause a denial of service (parsing error) or possibly have unspecified other impact via a crafted REST URL parameter, as demonstrated by parameters to admin/ and certain other files.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(66, 5, 'microsoft', 'windows', 'CVE-2011-4728', 'The Server Administration Panel in Parallels Plesk Panel 10.2.0_build1011110331.18 does not set the secure flag for a cookie in an https session, which makes it easier for remote attackers to capture this cookie by intercepting its transmission within an http session, as demonstrated by cookies used by login_up.php3 and certain other files.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(67, 5, 'microsoft', 'windows', 'CVE-2011-4729', 'The Server Administration Panel in Parallels Plesk Panel 10.2.0_build1011110331.18 does not include the HTTPOnly flag in a Set-Cookie header for a cookie, which makes it easier for remote attackers to obtain potentially sensitive information via script access to this cookie, as demonstrated by cookies used by login_up.php3 and certain other files.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(68, 5, 'microsoft', 'windows', 'CVE-2011-4730', 'The Server Administration Panel in Parallels Plesk Panel 10.2.0_build1011110331.18 generates a password form field without disabling the autocomplete feature, which makes it easier for remote attackers to bypass authentication by leveraging an unattended workstation, as demonstrated by forms in admin/reseller/login-info/ and certain other files.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(69, 5, 'microsoft', 'windows', 'CVE-2011-4731', 'The Server Administration Panel in Parallels Plesk Panel 10.2.0_build1011110331.18 includes an RFC 1918 IP address within a web page, which allows remote attackers to obtain potentially sensitive information by reading this page, as demonstrated by admin/home/admin and certain other files.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(70, 5, 'microsoft', 'windows', 'CVE-2011-4732', 'The Server Administration Panel in Parallels Plesk Panel 10.2.0_build1011110331.18 omits the Content-Type header\'s charset parameter for certain resources, which might allow remote attackers to have an unspecified impact by leveraging an interpretation conflict involving account/power-mode-logout and certain other files.  NOTE: it is possible that only clients, not the Plesk product, could be affected by this issue.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(71, 5, 'microsoft', 'windows', 'CVE-2011-4733', 'The Server Administration Panel in Parallels Plesk Panel 10.2.0_build1011110331.18 sends incorrect Content-Type headers for certain resources, which might allow remote attackers to have an unspecified impact by leveraging an interpretation conflict involving smb/admin-home/disable-featured-applications-promo and certain other files.  NOTE: it is possible that only clients, not the Plesk product, could be affected by this issue.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(72, 5, 'microsoft', 'windows', 'CVE-2011-4734', 'Multiple SQL injection vulnerabilities in the Control Panel in Parallels Plesk Panel 10.2.0 build 20110407.20 allow remote attackers to execute arbitrary SQL commands via crafted input to a PHP script, as demonstrated by file-manager/ and certain other files.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(73, 5, 'microsoft', 'windows', 'CVE-2011-4735', 'Multiple cross-site scripting (XSS) vulnerabilities in the Control Panel in Parallels Plesk Panel 10.2.0 build 20110407.20 allow remote attackers to inject arbitrary web script or HTML via crafted input to a PHP script, as demonstrated by smb/user/create and certain other files.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(74, 5, 'microsoft', 'windows', 'CVE-2011-4736', 'The Control Panel in Parallels Plesk Panel 10.2.0 build 20110407.20 receives cleartext password input over HTTP, which allows remote attackers to obtain sensitive information by sniffing the network, as demonstrated by forms in login_up.php3 and certain other files.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(75, 5, 'microsoft', 'windows', 'CVE-2011-4737', 'The Control Panel in Parallels Plesk Panel 10.2.0 build 20110407.20 includes a submitted password within an HTTP response body, which allows remote attackers to obtain sensitive information by sniffing the network, as demonstrated by password handling in client@2/domain@1/odbc/dsn@1/properties/.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(76, 5, 'microsoft', 'windows', 'CVE-2011-4738', 'The Control Panel in Parallels Plesk Panel 10.2.0 build 20110407.20 does not include the HTTPOnly flag in a Set-Cookie header for a cookie, which makes it easier for remote attackers to obtain potentially sensitive information via script access to this cookie, as demonstrated by cookies used by get_password.php and certain other files.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(77, 5, 'microsoft', 'windows', 'CVE-2011-4739', 'The Control Panel in Parallels Plesk Panel 10.2.0 build 20110407.20 generates a password form field without disabling the autocomplete feature, which makes it easier for remote attackers to bypass authentication by leveraging an unattended workstation, as demonstrated by forms in smb/my-profile and certain other files.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(78, 5, 'microsoft', 'windows', 'CVE-2011-4740', 'The Control Panel in Parallels Plesk Panel 10.2.0 build 20110407.20 generates web pages containing external links in response to GET requests with query strings for smb/app/search-data/catalogId/marketplace and certain other files, which makes it easier for remote attackers to obtain sensitive information by reading (1) web-server access logs or (2) web-server Referer logs, related to a \"cross-domain Referer leakage\" issue.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(79, 5, 'microsoft', 'windows', 'CVE-2011-4741', 'The Control Panel in Parallels Plesk Panel 10.2.0 build 20110407.20 includes a database connection string within a web page, which allows remote attackers to obtain potentially sensitive information by reading this page, as demonstrated by client@2/domain@1/hosting/aspdotnet/.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(80, 5, 'microsoft', 'windows', 'CVE-2011-4742', 'The Control Panel in Parallels Plesk Panel 10.2.0 build 20110407.20 has web pages containing e-mail addresses that are not intended for correspondence about the local application deployment, which allows remote attackers to obtain potentially sensitive information by reading a page, as demonstrated by smb/user/list and certain other files.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(81, 5, 'microsoft', 'windows', 'CVE-2011-4743', 'The Control Panel in Parallels Plesk Panel 10.2.0 build 20110407.20 omits the Content-Type header\'s charset parameter for certain resources, which might allow remote attackers to have an unspecified impact by leveraging an interpretation conflict involving smb/user/create and certain other files.  NOTE: it is possible that only clients, not the Plesk product, could be affected by this issue.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(82, 5, 'microsoft', 'windows', 'CVE-2011-4744', 'The Control Panel in Parallels Plesk Panel 10.2.0 build 20110407.20 sends incorrect Content-Type headers for certain resources, which might allow remote attackers to have an unspecified impact by leveraging an interpretation conflict involving smb/admin-home/featured-applications/ and certain other files.  NOTE: it is possible that only clients, not the Plesk product, could be affected by this issue.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(83, 5, 'microsoft', 'windows', 'CVE-2011-5049', 'MySQL 5.5.8, when running on Windows, allows remote attackers to cause a denial of service (NULL pointer dereference) via a crafted packet to TCP port 3306.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(84, 5, 'microsoft', 'windows', 'CVE-2012-0014', 'Microsoft .NET Framework 2.0 SP2, 3.5.1, and 4, and Silverlight 4 before 4.1.10111, does not properly restrict access to memory associated with unmanaged objects, which allows remote attackers to execute arbitrary code via (1) a crafted XAML browser application (aka XBAP), (2) a crafted ASP.NET application, (3) a crafted .NET Framework application, or (4) a crafted Silverlight application, aka \".NET Framework Unmanaged Objects Vulnerability.\"', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(85, 5, 'microsoft', 'windows', 'CVE-2012-0584', 'The Internationalized Domain Name (IDN) feature in Apple Safari before 5.1.4 on Windows does not properly restrict the characters in URLs, which allows remote attackers to spoof a domain name via unspecified homoglyphs.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(86, 5, 'microsoft', 'windows', 'CVE-2012-0132', 'Cross-site scripting (XSS) vulnerability in HP Business Availability Center (BAC) 9.01 allows remote attackers to inject arbitrary web script or HTML via unspecified vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(87, 5, 'microsoft', 'windows', 'CVE-2012-2376', 'Buffer overflow in the com_print_typeinfo function in PHP 5.4.3 and earlier on Windows allows remote attackers to execute arbitrary code via crafted arguments that trigger incorrect handling of COM object VARIANT types, as exploited in the wild in May 2012.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(88, 5, 'microsoft', 'windows', 'CVE-2012-2816', 'Google Chrome before 20.0.1132.43 on Windows does not properly isolate sandboxed processes, which might allow remote attackers to cause a denial of service (process interference) via unspecified vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(89, 5, 'microsoft', 'windows', 'CVE-2012-2847', 'Google Chrome before 21.0.1180.57 on Mac OS X and Linux, and before 21.0.1180.60 on Windows and Chrome Frame, does not request user confirmation before continuing a large series of downloads, which allows user-assisted remote attackers to cause a denial of service (resource consumption) via a crafted web site.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(90, 5, 'microsoft', 'windows', 'CVE-2012-2848', 'The drag-and-drop implementation in Google Chrome before 21.0.1180.57 on Mac OS X and Linux, and before 21.0.1180.60 on Windows and Chrome Frame, allows user-assisted remote attackers to bypass intended file access restrictions via a crafted web site.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(91, 5, 'microsoft', 'windows', 'CVE-2012-2849', 'Off-by-one error in the GIF decoder in Google Chrome before 21.0.1180.57 on Mac OS X and Linux, and before 21.0.1180.60 on Windows and Chrome Frame, allows remote attackers to cause a denial of service (out-of-bounds read) via a crafted image.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(92, 5, 'microsoft', 'windows', 'CVE-2012-2850', 'Multiple unspecified vulnerabilities in the PDF functionality in Google Chrome before 21.0.1180.57 on Mac OS X and Linux, and before 21.0.1180.60 on Windows and Chrome Frame, allow remote attackers to have an unknown impact via a crafted document.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(93, 5, 'microsoft', 'windows', 'CVE-2012-2851', 'Multiple integer overflows in the PDF functionality in Google Chrome before 21.0.1180.57 on Mac OS X and Linux, and before 21.0.1180.60 on Windows and Chrome Frame, allow remote attackers to cause a denial of service or possibly have unspecified other impact via a crafted document.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(94, 5, 'microsoft', 'windows', 'CVE-2012-2852', 'The PDF functionality in Google Chrome before 21.0.1180.57 on Mac OS X and Linux, and before 21.0.1180.60 on Windows and Chrome Frame, does not properly handle object linkage, which allows remote attackers to cause a denial of service (use-after-free) or possibly have unspecified other impact via a crafted document.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(95, 5, 'microsoft', 'windows', 'CVE-2012-2853', 'The webRequest API in Google Chrome before 21.0.1180.57 on Mac OS X and Linux, and before 21.0.1180.60 on Windows and Chrome Frame, does not properly interact with the Chrome Web Store, which allows remote attackers to cause a denial of service or possibly have unspecified other impact via a crafted web site.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(96, 5, 'microsoft', 'windows', 'CVE-2012-2854', 'Google Chrome before 21.0.1180.57 on Mac OS X and Linux, and before 21.0.1180.60 on Windows and Chrome Frame, allows remote attackers to obtain potentially sensitive information about pointer values by leveraging access to a WebUI renderer process.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(97, 5, 'microsoft', 'windows', 'CVE-2012-2855', 'Use-after-free vulnerability in the PDF functionality in Google Chrome before 21.0.1180.57 on Mac OS X and Linux, and before 21.0.1180.60 on Windows and Chrome Frame, allows remote attackers to cause a denial of service or possibly have unspecified other impact via a crafted document.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(98, 5, 'microsoft', 'windows', 'CVE-2012-2856', 'The PDF functionality in Google Chrome before 21.0.1180.57 on Mac OS X and Linux, and before 21.0.1180.60 on Windows and Chrome Frame, allows remote attackers to cause a denial of service or possibly have unspecified other impact via vectors that trigger out-of-bounds write operations.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(99, 5, 'microsoft', 'windows', 'CVE-2012-2857', 'Use-after-free vulnerability in the Cascading Style Sheets (CSS) DOM implementation in Google Chrome before 21.0.1180.57 on Mac OS X and Linux, and before 21.0.1180.60 on Windows and Chrome Frame, allows remote attackers to cause a denial of service or possibly have unspecified other impact via a crafted document.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(100, 5, 'microsoft', 'windows', 'CVE-2012-2858', 'Buffer overflow in the WebP decoder in Google Chrome before 21.0.1180.57 on Mac OS X and Linux, and before 21.0.1180.60 on Windows and Chrome Frame, allows remote attackers to cause a denial of service or possibly have unspecified other impact via a crafted WebP image.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(101, 5, 'microsoft', 'windows', 'CVE-2012-2860', 'The date-picker implementation in Google Chrome before 21.0.1180.57 on Mac OS X and Linux, and before 21.0.1180.60 on Windows and Chrome Frame, allows user-assisted remote attackers to cause a denial of service or possibly have unspecified other impact via a crafted web site.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(102, 5, 'microsoft', 'windows', 'CVE-2012-4145', 'Unspecified vulnerability in Opera before 12.01 on Windows and UNIX, and before 11.66 and 12.x before 12.01 on Mac OS X, has unknown impact and attack vectors, related to a \"low severity issue.\"', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(103, 5, 'microsoft', 'windows', 'CVE-2012-4363', 'Multiple unspecified vulnerabilities in Adobe Reader through 10.1.4 allow remote attackers to cause a denial of service (application crash) or possibly execute arbitrary code via a crafted PDF document, related to \"sixteen more crashes affecting Windows, OS X, or both systems.\"', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(104, 5, 'microsoft', 'windows', 'CVE-2012-2971', 'The server in CA ARCserve Backup r12.5, r15, and r16 on Windows does not properly process RPC requests, which allows remote attackers to execute arbitrary code or cause a denial of service via a crafted request.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(105, 5, 'microsoft', 'windows', 'CVE-2012-2972', 'The (1) server and (2) agent components in CA ARCserve Backup r12.5, r15, and r16 on Windows do not properly validate RPC requests, which allows remote attackers to cause a denial of service (service crash) via a crafted request.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(106, 5, 'microsoft', 'windows', 'CVE-2012-5154', 'Integer overflow in Google Chrome before 24.0.1312.52 on Windows allows attackers to cause a denial of service or possibly have unspecified other impact via vectors related to allocation of shared memory.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(107, 5, 'microsoft', 'windows', 'CVE-2013-0830', 'The IPC layer in Google Chrome before 24.0.1312.52 on Windows omits a NUL character required for termination of an unspecified data structure, which has unknown impact and attack vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(108, 5, 'microsoft', 'windows', 'CVE-2013-0879', 'Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, does not properly implement web audio nodes, which allows remote attackers to cause a denial of service (memory corruption) or possibly have unspecified other impact via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(109, 5, 'microsoft', 'windows', 'CVE-2013-0880', 'Use-after-free vulnerability in Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, allows remote attackers to cause a denial of service or possibly have unspecified other impact via vectors related to databases.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(110, 5, 'microsoft', 'windows', 'CVE-2013-0881', 'Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, allows remote attackers to cause a denial of service (incorrect read operation) via crafted data in the Matroska container format.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(111, 5, 'microsoft', 'windows', 'CVE-2013-0882', 'Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, allows remote attackers to cause a denial of service (incorrect memory access) or possibly have unspecified other impact via a large number of SVG parameters.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(112, 5, 'microsoft', 'windows', 'CVE-2013-0883', 'Skia, as used in Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, allows remote attackers to cause a denial of service (incorrect read operation) via unspecified vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(113, 5, 'microsoft', 'windows', 'CVE-2013-0884', 'Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, does not properly load Native Client (aka NaCl) code, which has unspecified impact and attack vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(114, 5, 'microsoft', 'windows', 'CVE-2013-0885', 'Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, does not properly restrict API privileges during interaction with the Chrome Web Store, which has unspecified impact and attack vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(115, 5, 'microsoft', 'windows', 'CVE-2013-0887', 'The developer-tools process in Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, does not properly restrict privileges during interaction with a connected server, which has unspecified impact and attack vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(116, 5, 'microsoft', 'windows', 'CVE-2013-0888', 'Skia, as used in Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, allows remote attackers to cause a denial of service (out-of-bounds read) via vectors related to a \"user gesture check for dangerous file downloads.\"', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(117, 5, 'microsoft', 'windows', 'CVE-2013-0889', 'Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, does not properly enforce a user gesture requirement before proceeding with a file download, which might make it easier for remote attackers to execute arbitrary code via a crafted file.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(118, 5, 'microsoft', 'windows', 'CVE-2013-0890', 'Multiple unspecified vulnerabilities in the IPC layer in Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, allow remote attackers to cause a denial of service (memory corruption) or possibly have other impact via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(119, 5, 'microsoft', 'windows', 'CVE-2013-0891', 'Integer overflow in Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, allows remote attackers to cause a denial of service or possibly have unspecified other impact via a blob.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(120, 5, 'microsoft', 'windows', 'CVE-2013-0892', 'Multiple unspecified vulnerabilities in the IPC layer in Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, allow remote attackers to cause a denial of service or possibly have other impact via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(121, 5, 'microsoft', 'windows', 'CVE-2013-0893', 'Race condition in Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, allows remote attackers to cause a denial of service or possibly have unspecified other impact via vectors related to media.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(122, 5, 'microsoft', 'windows', 'CVE-2013-0894', 'Buffer overflow in the vorbis_parse_setup_hdr_floors function in the Vorbis decoder in vorbisdec.c in libavcodec in FFmpeg through 1.1.3, as used in Google Chrome before 25.0.1364.97 on Windows and Linux and before 25.0.1364.99 on Mac OS X and other products, allows remote attackers to cause a denial of service (divide-by-zero error or out-of-bounds array access) or possibly have unspecified other impact via vectors involving a zero value for a bark map size.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(123, 5, 'microsoft', 'windows', 'CVE-2013-0895', 'Google Chrome before 25.0.1364.97 on Linux, and before 25.0.1364.99 on Mac OS X, does not properly handle pathnames during copy operations, which might make it easier for remote attackers to execute arbitrary programs via unspecified vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(124, 5, 'microsoft', 'windows', 'CVE-2013-0896', 'Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, does not properly manage memory during message handling for plug-ins, which allows remote attackers to cause a denial of service or possibly have unspecified other impact via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(125, 5, 'microsoft', 'windows', 'CVE-2013-0897', 'Off-by-one error in the PDF functionality in Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, allows remote attackers to cause a denial of service via a crafted document.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(126, 5, 'microsoft', 'windows', 'CVE-2013-0898', 'Use-after-free vulnerability in Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, allows remote attackers to cause a denial of service or possibly have unspecified other impact via vectors involving a URL.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(127, 5, 'microsoft', 'windows', 'CVE-2013-0899', 'Integer overflow in the padding implementation in the opus_packet_parse_impl function in src/opus_decoder.c in Opus before 1.0.2, as used in Google Chrome before 25.0.1364.97 on Windows and Linux and before 25.0.1364.99 on Mac OS X and other products, allows remote attackers to cause a denial of service (out-of-bounds read) via a long packet.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(128, 5, 'microsoft', 'windows', 'CVE-2013-0900', 'Race condition in the International Components for Unicode (ICU) functionality in Google Chrome before 25.0.1364.97 on Windows and Linux, and before 25.0.1364.99 on Mac OS X, allows remote attackers to cause a denial of service or possibly have unspecified other impact via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(129, 5, 'microsoft', 'windows', 'CVE-2013-0680', 'Stack-based buffer overflow in the web server in Cogent Real-Time Systems Cogent DataHub before 7.3.0, OPC DataHub before 6.4.22, Cascade DataHub before 6.4.22 on Windows, and DataHub QuickTrend before 7.3.0 allows remote attackers to cause a denial of service (daemon crash) or possibly execute arbitrary code via a long HTTP header.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(130, 5, 'microsoft', 'windows', 'CVE-2013-0681', 'Cogent Real-Time Systems Cogent DataHub before 7.3.0, OPC DataHub before 6.4.22, Cascade DataHub before 6.4.22 on Windows, and DataHub QuickTrend before 7.3.0 allow remote attackers to cause a denial of service (NULL pointer dereference and application crash) via malformed data in a formatted text command.', '2026-03-05 15:22:51', '2026-03-05 15:22:51');
INSERT INTO `vulnerabilities` (`id`, `target_id`, `vendor`, `product`, `cve_id`, `description`, `first_seen`, `last_seen`) VALUES
(131, 5, 'microsoft', 'windows', 'CVE-2013-0682', 'Cogent Real-Time Systems Cogent DataHub before 7.3.0, OPC DataHub before 6.4.22, Cascade DataHub before 6.4.22 on Windows, and DataHub QuickTrend before 7.3.0 do not properly handle exceptions, which allows remote attackers to cause a denial of service (application crash) or possibly execute arbitrary code via malformed data in a formatted text command, leading to out-of-bounds access to (1) heap or (2) stack memory.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(132, 5, 'microsoft', 'windows', 'CVE-2013-0683', 'The DataSim and DataPid demonstration clients in Cogent Real-Time Systems Cogent DataHub before 7.3.0, OPC DataHub before 6.4.22, Cascade DataHub before 6.4.22 on Windows, and DataHub QuickTrend before 7.3.0 allow remote servers to cause a denial of service (incorrect pointer access and client crash) via malformed data in a formatted text command.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(133, 5, 'microsoft', 'windows', 'CVE-2013-0941', 'EMC RSA Authentication API before 8.1 SP1, RSA Web Agent before 5.3.5 for Apache Web Server, RSA Web Agent before 5.3.5 for IIS, RSA PAM Agent before 7.0, and RSA Agent before 6.1.4 for Microsoft Windows use an improper encryption algorithm and a weak key for maintaining the stored data of the node secret for the SecurID Authentication API, which allows local users to obtain sensitive information via cryptographic attacks on this data.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(134, 5, 'microsoft', 'windows', 'CVE-2013-2854', 'Google Chrome before 27.0.1453.110 on Windows provides an incorrect handle to a renderer process in unspecified circumstances, which allows remote attackers to cause a denial of service or possibly have other impact via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(135, 5, 'microsoft', 'windows', 'CVE-2013-4669', 'FortiClient before 4.3.5.472 on Windows, before 4.0.3.134 on Mac OS X, and before 4.0 on Android; FortiClient Lite before 4.3.4.461 on Windows; FortiClient Lite 2.0 through 2.0.0223 on Android; and FortiClient SSL VPN before 4.0.2258 on Linux proceed with an SSL session after determining that the server\'s X.509 certificate is invalid, which allows man-in-the-middle attackers to obtain sensitive information by leveraging a password transmission that occurs before the user warning about the certificate problem.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(136, 5, 'microsoft', 'windows', 'CVE-2013-2874', 'Google Chrome before 28.0.1500.71 on Windows, when an Nvidia GPU is used, allows remote attackers to bypass intended restrictions on access to screen data via vectors involving IPC transmission of GL textures.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(137, 5, 'microsoft', 'windows', 'CVE-2013-2900', 'The FilePath::ReferencesParent function in files/file_path.cc in Google Chrome before 29.0.1547.57 on Windows does not properly handle pathname components composed entirely of . (dot) and whitespace characters, which allows remote attackers to conduct directory traversal attacks via a crafted directory name.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(138, 5, 'microsoft', 'windows', 'CVE-2013-2914', 'Use-after-free vulnerability in the color-chooser dialog in Google Chrome before 30.0.1599.66 on Windows allows remote attackers to cause a denial of service or possibly have unspecified other impact via vectors related to color_chooser_dialog.cc and color_chooser_win.cc in browser/ui/views/.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(139, 5, 'microsoft', 'windows', 'CVE-2014-1705', 'Google V8, as used in Google Chrome before 33.0.1750.152 on OS X and Linux and before 33.0.1750.154 on Windows, allows remote attackers to cause a denial of service (memory corruption) or possibly have unspecified other impact via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(140, 5, 'microsoft', 'windows', 'CVE-2014-1713', 'Use-after-free vulnerability in the AttributeSetter function in bindings/templates/attributes.cpp in the bindings in Blink, as used in Google Chrome before 33.0.1750.152 on OS X and Linux and before 33.0.1750.154 on Windows, allows remote attackers to cause a denial of service or possibly have unspecified other impact via vectors involving the document.location value.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(141, 5, 'microsoft', 'windows', 'CVE-2014-1714', 'The ScopedClipboardWriter::WritePickledData function in ui/base/clipboard/scoped_clipboard_writer.cc in Google Chrome before 33.0.1750.152 on OS X and Linux and before 33.0.1750.154 on Windows does not verify a certain format value, which allows remote attackers to cause a denial of service or possibly have unspecified other impact via vectors related to the clipboard.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(142, 5, 'microsoft', 'windows', 'CVE-2014-1715', 'Directory traversal vulnerability in Google Chrome before 33.0.1750.152 on OS X and Linux and before 33.0.1750.154 on Windows has unspecified impact and attack vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(143, 5, 'microsoft', 'windows', 'CVE-2014-0506', 'Use-after-free vulnerability in Adobe Flash Player before 11.7.700.275 and 11.8.x through 13.0.x before 13.0.0.182 on Windows and OS X and before 11.2.202.350 on Linux, Adobe AIR before 13.0.0.83 on Android, Adobe AIR SDK before 13.0.0.83, and Adobe AIR SDK & Compiler before 13.0.0.83 allows remote attackers to execute arbitrary code, and possibly bypass an Internet Explorer sandbox protection mechanism, via unspecified vectors, as demonstrated by VUPEN during a Pwn2Own competition at CanSecWest 2014.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(144, 5, 'microsoft', 'windows', 'CVE-2014-1730', 'Google V8, as used in Google Chrome before 34.0.1847.131 on Windows and OS X and before 34.0.1847.132 on Linux, does not properly store internationalization metadata, which allows remote attackers to bypass intended access restrictions by leveraging \"type confusion\" and reading property values, related to i18n.js and runtime.cc.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(145, 5, 'microsoft', 'windows', 'CVE-2014-1731', 'core/html/HTMLSelectElement.cpp in the DOM implementation in Blink, as used in Google Chrome before 34.0.1847.131 on Windows and OS X and before 34.0.1847.132 on Linux, does not properly check renderer state upon a focus event, which allows remote attackers to cause a denial of service or possibly have unspecified other impact via vectors that leverage \"type confusion\" for SELECT elements.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(146, 5, 'microsoft', 'windows', 'CVE-2014-1732', 'Use-after-free vulnerability in browser/ui/views/speech_recognition_bubble_views.cc in Google Chrome before 34.0.1847.131 on Windows and OS X and before 34.0.1847.132 on Linux allows remote attackers to cause a denial of service or possibly have unspecified other impact via an INPUT element that triggers the presence of a Speech Recognition Bubble window for an incorrect duration.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(147, 5, 'microsoft', 'windows', 'CVE-2014-1733', 'The PointerCompare function in codegen.cc in Seccomp-BPF, as used in Google Chrome before 34.0.1847.131 on Windows and OS X and before 34.0.1847.132 on Linux, does not properly merge blocks, which might allow remote attackers to bypass intended sandbox restrictions by leveraging renderer access.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(148, 5, 'microsoft', 'windows', 'CVE-2014-1734', 'Multiple unspecified vulnerabilities in Google Chrome before 34.0.1847.131 on Windows and OS X and before 34.0.1847.132 on Linux allow attackers to cause a denial of service or possibly have other impact via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(149, 5, 'microsoft', 'windows', 'CVE-2014-1735', 'Multiple unspecified vulnerabilities in Google V8 before 3.24.35.33, as used in Google Chrome before 34.0.1847.131 on Windows and OS X and before 34.0.1847.132 on Linux, allow attackers to cause a denial of service or possibly have other impact via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(150, 5, 'microsoft', 'windows', 'CVE-2014-1736', 'Integer overflow in api.cc in Google V8, as used in Google Chrome before 34.0.1847.131 on Windows and OS X and before 34.0.1847.132 on Linux, allows remote attackers to cause a denial of service or possibly have unspecified other impact via a large length value.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(151, 5, 'microsoft', 'windows', 'CVE-2014-3166', 'The Public Key Pinning (PKP) implementation in Google Chrome before 36.0.1985.143 on Windows, OS X, and Linux, and before 36.0.1985.135 on Android, does not correctly consider the properties of SPDY connections, which allows remote attackers to obtain sensitive information by leveraging the use of multiple domain names.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(152, 5, 'microsoft', 'windows', 'CVE-2013-7144', 'LINE 3.2.1.83 and earlier on Windows and 3.2.1 and earlier on OS X does not verify X.509 certificates from SSL servers, which allows man-in-the-middle attackers to spoof servers and obtain sensitive information via a crafted certificate.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(153, 5, 'microsoft', 'windows', 'CVE-2014-7237', 'lib/TWiki/Sandbox.pm in TWiki 6.0.0 and earlier, when running on Windows, allows remote attackers to bypass intended access restrictions and upload files with restricted names via a null byte (%00) in a filename to bin/upload.cgi, as demonstrated using .htaccess to execute arbitrary code.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(154, 5, 'microsoft', 'windows', 'CVE-2015-0305', 'Adobe Flash Player before 13.0.0.260 and 14.x through 16.x before 16.0.0.257 on Windows and OS X and before 11.2.202.429 on Linux, Adobe AIR before 16.0.0.245 on Windows and OS X and before 16.0.0.272 on Android, Adobe AIR SDK before 16.0.0.272, and Adobe AIR SDK & Compiler before 16.0.0.272 allow attackers to execute arbitrary code by leveraging an unspecified \"type confusion.\"', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(155, 5, 'microsoft', 'windows', 'CVE-2015-1209', 'Use-after-free vulnerability in the VisibleSelection::nonBoundaryShadowTreeRootNode function in core/editing/VisibleSelection.cpp in the DOM implementation in Blink, as used in Google Chrome before 40.0.2214.111 on Windows, OS X, and Linux and before 40.0.2214.109 on Android, allows remote attackers to cause a denial of service or possibly have unspecified other impact via crafted JavaScript code that triggers improper handling of a shadow-root anchor.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(156, 5, 'microsoft', 'windows', 'CVE-2015-1210', 'The V8ThrowException::createDOMException function in bindings/core/v8/V8ThrowException.cpp in the V8 bindings in Blink, as used in Google Chrome before 40.0.2214.111 on Windows, OS X, and Linux and before 40.0.2214.109 on Android, does not properly consider frame access restrictions during the throwing of an exception, which allows remote attackers to bypass the Same Origin Policy via a crafted web site.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(157, 5, 'microsoft', 'windows', 'CVE-2015-1211', 'The OriginCanAccessServiceWorkers function in content/browser/service_worker/service_worker_dispatcher_host.cc in Google Chrome before 40.0.2214.111 on Windows, OS X, and Linux and before 40.0.2214.109 on Android does not properly restrict the URI scheme during a ServiceWorker registration, which allows remote attackers to gain privileges via a filesystem: URI.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(158, 5, 'microsoft', 'windows', 'CVE-2015-1212', 'Multiple unspecified vulnerabilities in Google Chrome before 40.0.2214.111 on Windows, OS X, and Linux and before 40.0.2214.109 on Android allow attackers to cause a denial of service or possibly have other impact via unknown vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(159, 5, 'microsoft', 'windows', 'CVE-2015-0884', 'Unquoted Windows search path vulnerability in Toshiba Bluetooth Stack for Windows before 9.10.32(T) and Service Station before 2.2.14 allows local users to gain privileges via a Trojan horse application with a name composed of an initial substring of a path that contains a space character.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(160, 5, 'microsoft', 'windows', 'CVE-2015-1233', 'Google Chrome before 41.0.2272.118 does not properly handle the interaction of IPC, the Gamepad API, and Google V8, which allows remote attackers to execute arbitrary code via unspecified vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(161, 5, 'microsoft', 'windows', 'CVE-2015-1234', 'Race condition in gpu/command_buffer/service/gles2_cmd_decoder.cc in Google Chrome before 41.0.2272.118 allows remote attackers to cause a denial of service (buffer overflow) or possibly have unspecified other impact by manipulating OpenGL ES commands.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(162, 5, 'microsoft', 'windows', 'CVE-2015-1830', 'Directory traversal vulnerability in the fileserver upload/download functionality for blob messages in Apache ActiveMQ 5.x before 5.11.2 for Windows allows remote attackers to create JSP files in arbitrary directories via unspecified vectors.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(163, 5, 'microsoft', 'windows', 'CVE-2015-4796', 'Unspecified vulnerability in the Java VM component in Oracle Database Server 11.2.0.4, 12.1.0.1, and 12.1.0.2, when running on Windows, allows remote authenticated users to affect confidentiality, integrity, and availability via unknown vectors, a different vulnerability than CVE-2015-4888.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(164, 5, 'microsoft', 'windows', 'CVE-2015-4642', 'The escapeshellarg function in ext/standard/exec.c in PHP before 5.4.42, 5.5.x before 5.5.26, and 5.6.x before 5.6.10 on Windows allows remote attackers to execute arbitrary OS commands via a crafted string to an application that accepts command-line arguments for a call to the PHP system function.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(165, 5, 'microsoft', 'windows', 'CVE-2016-0749', 'The smartcard interaction in SPICE allows remote attackers to cause a denial of service (QEMU-KVM process crash) or possibly execute arbitrary code via vectors related to connecting to a guest VM, which triggers a heap-based buffer overflow.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(166, 5, 'microsoft', 'windows', 'CVE-2016-2150', 'SPICE allows local guest OS users to read from or write to arbitrary host memory locations via crafted primary surface parameters, a similar issue to CVE-2015-5261.', '2026-03-05 15:22:51', '2026-03-05 15:22:51'),
(167, 5, 'microsoft', 'windows', 'CVE-2016-3684', 'SAP Download Manager 2.1.142 and earlier uses a hardcoded encryption key to protect stored data, which allows context-dependent attackers to obtain sensitive configuration information by leveraging knowledge of this key, aka SAP Security Note 2282338.', '2026-03-05 15:22:51', '2026-03-05 15:22:51');
